dtsPropsFor.Button:
/** Visual style. MUI variants plus the OpenLeague 'marketing' CTA variants. */
  variant?: 'text' | 'outlined' | 'contained' | 'marketing' | 'marketingSecondary';
  /** Theme color. */
  color?: 'inherit' | 'primary' | 'secondary' | 'success' | 'error' | 'info' | 'warning';
  size?: 'small' | 'medium' | 'large';
  disabled?: boolean;
  disableElevation?: boolean;
  fullWidth?: boolean;
  /** Node rendered before the label. */
  startIcon?: React.ReactNode;
  /** Node rendered after the label. */
  endIcon?: React.ReactNode;
  /** Renders the button as an anchor when set. */
  href?: string;
  type?: 'button' | 'submit' | 'reset';
  onClick?: React.MouseEventHandler<HTMLButtonElement>;
  children?: React.ReactNode;
  sx?: Record<string, unknown>;

dtsPropsFor.Input:
/** Field label. */
  label?: React.ReactNode;
  value?: unknown;
  defaultValue?: unknown;
  onChange?: React.ChangeEventHandler<HTMLInputElement | HTMLTextAreaElement>;
  placeholder?: string;
  /** HTML input type, e.g. 'text' | 'email' | 'password' | 'number'. */
  type?: string;
  variant?: 'outlined' | 'filled' | 'standard';
  size?: 'small' | 'medium';
  color?: 'primary' | 'secondary' | 'success' | 'error' | 'info' | 'warning';
  required?: boolean;
  disabled?: boolean;
  /** Marks the field as invalid (red outline). */
  error?: boolean;
  helperText?: React.ReactNode;
  fullWidth?: boolean;
  multiline?: boolean;
  rows?: number;
  /** Render as a dropdown when true. */
  select?: boolean;
  sx?: Record<string, unknown>;

dtsPropsFor.Card:
/** 'elevation' (default) | 'outlined' | the OpenLeague 'marketing' gradient card. */
  variant?: 'elevation' | 'outlined' | 'marketing';
  /** Shadow depth (0-24) when variant is 'elevation'. */
  elevation?: number;
  raised?: boolean;
  /** Compose with the Card.Content and Card.Actions subcomponents. */
  children?: React.ReactNode;
  sx?: Record<string, unknown>;

dtsPropsFor.Dialog:
/** Whether the dialog is visible. */
  open: boolean;
  /** Called on backdrop click or Escape. */
  onClose?: (event: object, reason: 'backdropClick' | 'escapeKeyDown') => void;
  fullWidth?: boolean;
  maxWidth?: 'xs' | 'sm' | 'md' | 'lg' | 'xl' | false;
  fullScreen?: boolean;
  scroll?: 'body' | 'paper';
  /** Compose with the Dialog.Title, Dialog.Content and Dialog.Actions subcomponents. */
  children?: React.ReactNode;
  sx?: Record<string, unknown>;

dtsPropsFor.Pagination:
/** 1-based index of the current page. */
  currentPage: number;
  totalPages: number;
  totalItems: number;
  itemsPerPage: number;
  onPageChange: (page: number) => void;
  onItemsPerPageChange?: (itemsPerPage: number) => void;
  itemsPerPageOptions?: number[];
  isLoading?: boolean;
  showItemsPerPage?: boolean;
  /** 'full' shows the complete pager; 'loadMore' shows a single Load More button. */
  variant?: 'full' | 'loadMore';

dtsPropsFor.Logo:
/** Size preset: small 32px, medium 44px, large 56px, xlarge 64px. */
  size?: 'small' | 'medium' | 'large' | 'xlarge';
  width?: number;
  height?: number;
  /** 'default' has a hover scale effect; 'footer' is static and unlinked. */
  variant?: 'default' | 'footer';
  /** Link destination; null renders without a link wrapper. */
  href?: string | null;
  priority?: boolean;
  /** Show the "OpenLeague" wordmark next to the icon. */
  showText?: boolean;
  /** Responsive wordmark visibility per breakpoint. */
  showTextResponsive?: boolean | { xs?: boolean; sm?: boolean; md?: boolean; lg?: boolean; xl?: boolean };
  sx?: Record<string, unknown>;
  className?: string;

dtsPropsFor.BrandLogo:
/** 'icon' circular mark | 'full' branded logo with tagline | 'compact' medium branded logo. */
  variant?: 'icon' | 'full' | 'compact';
  /** Size preset: small | medium | large | xlarge. */
  size?: 'small' | 'medium' | 'large' | 'xlarge';
  width?: number;
  height?: number;
  /** Link destination; null renders without a link wrapper. */
  href?: string | null;
  priority?: boolean;
  /** Hover scale effect. */
  interactive?: boolean;
  sx?: Record<string, unknown>;
  className?: string;

dtsPropsFor.PlayerCard:
/** Roster entry (a Player record). */
  player: {
    id: string;
    name: string;
    email: string | null;
    phone: string | null;
    emergencyContact: string | null;
    emergencyPhone: string | null;
    jerseyNumber: number | null;
    usahMemberId: string | null;
  };
  /** Admins see edit/delete controls plus emergency-contact and USA Hockey fields. */
  isAdmin: boolean;
  teamId: string;
  /** Invoked when the edit icon is pressed. */
  onEdit: () => void;

dtsPropsFor.VenueCard:
/** Venue summary. Clicking the card navigates to the venue detail page. */
  venue: {
    id: string;
    name: string;
    address: string | null;
    city: string | null;
    state: string | null;
    /** Playing surface: ICE | TURF | COURT | FIELD | OTHER. */
    surfaceType: string;
    capacity: number | null;
    /** PUBLIC | LEAGUE | TEAM. */
    visibility: string;
    isActive: boolean;
    team: { id: string; name: string } | null;
    league: { id: string; name: string } | null;
  };

dtsPropsFor.ConflictWarning:
/** Scheduling conflicts to surface in a warning Alert. */
  conflicts: Array<{
    teamId: string;
    teamName: string;
    conflictingEvent: { id: string; title: string; startAt: Date };
  }>;
  /** Optional clickable alternative time-slot chips. */
  suggestions?: Array<{ startAt: Date; reason: string }>;
  /** League admins can override conflicts. */
  canOverride?: boolean;
  onSuggestionSelect?: (suggestion: { startAt: Date; reason: string }) => void;
  onOverrideConflicts?: () => void;
  isOverriding?: boolean;

dtsPropsFor.EventCard:
/** Event id (used to build the detail link). */
  id: string;
  type: 'GAME' | 'PRACTICE';
  title: string;
  /** ISO date-time string (or Date). */
  startAt: string;
  location: string;
  opponent?: string | null;
  /** When set, links to the league-scoped event page. */
  leagueId?: string;
  homeTeam?: { id: string; name: string } | null;
  awayTeam?: { id: string; name: string } | null;
  teamName?: string;

dtsPropsFor.TeamCard:
/** Team summary. */
  team: {
    id: string;
    name: string;
    sport: string;
    season: string;
    league?: { id: string; name: string } | null;
    division?: { id: string; name: string } | null;
    _count?: { players: number; events: number };
  };
  /** 'ADMIN' shows a Manage action and Team Admin badge. */
  role: 'ADMIN' | 'MEMBER';
  /** Show league/division chips (league mode). */
  showLeagueInfo?: boolean;
  /** Show the players/events stat grid. */
  showStats?: boolean;

dtsPropsFor.LeagueOverviewCard:
/** League summary with aggregate counts. */
  league: {
    id: string;
    name: string;
    sport: string;
    _count: { teams: number; players: number; events: number; divisions: number };
  };
  userRole: 'LEAGUE_ADMIN' | 'TEAM_ADMIN' | 'MEMBER';
  /** Optional recent-activity panel. */
  recentActivity?: { description: string; timestamp: Date };
